def esc(val):
    if not val:
        return ""
    return (
        val.replace("\\", "\\\\")   # escape backslashes
           .replace('"', '\\"')     # escape quotes
           .replace("\r\n", "\n")   # normalize Windows line endings
           .replace("\r", "\n")     # normalize old Mac line endings
           .replace("\n", "\\n")    # escape newlines for JSON
    )

