script_behavior_tracker = """
<script type="text/javascript">
  document.addEventListener("DOMContentLoaded", function () {
    const textarea = document.querySelector('[name="Q7_1"] textarea') || document.querySelector('[name="Q7_1"]');
    if(!textarea) return;

    const INTERACTION_TYPES = { KEYSTROKE: 'KEYSTROKE', COPYPASTE: 'COPY_AND_PASTE' };
    const QUESTION_ID = "Q7_1";
    let startTime = null;
    let interactionData = JSON.parse(sessionStorage.getItem("interaction_data") || "[]");

    const pushInteraction = (value, interactionType) => {
      interactionData.push({ value, interactionType, timestamp: new Date().toISOString() });
      sessionStorage.setItem("interaction_data", JSON.stringify(interactionData));
    };

    textarea.addEventListener('input', function(e){
      if (e.inputType === 'insertFromPaste') return;
      if (!startTime) { startTime = Date.now(); }
      pushInteraction(e.target.value, INTERACTION_TYPES.KEYSTROKE);
    });

    textarea.addEventListener('paste', function(e){
      if (!startTime) { startTime = Date.now(); }
      const cursorPos = e.target.selectionStart;
      const current = e.target.value;
      const pasted = e.clipboardData ? e.clipboardData.getData('text') : '';
      const newText = current.slice(0, cursorPos) + pasted + current.slice(cursorPos);
      pushInteraction(newText, INTERACTION_TYPES.COPYPASTE);
    });

    const saveData = function () {
      sessionStorage.setItem(QUESTION_ID, JSON.stringify({ qualityCheck: 'BAS', dataPointId: QUESTION_ID, interactionData: interactionData }));
      const hiddenInput = document.querySelector('#question_ReDem_BAS_Data input');
      if(hiddenInput){ hiddenInput.value = JSON.stringify(interactionData); }
    };

    window.addEventListener('beforeunload', saveData);
  });
</script>
"""
gv.survey.rawHeaders.append(script_behavior_tracker)
